{
  "executive_summary": "Integration architecture for a logistics platform connecting three external systems (SAP ERP via SFTP/XML, DHL Carrier via REST/webhooks, Analytics via Kafka) using an event-driven backbone with dedicated Anti-Corruption Layers per integration. The design isolates each external system behind adapters, uses an internal event bus as the single source of truth, and ensures that no external system's failure or latency cascades into the core domain.",

  "architecture": {
    "components": [
      {
        "name": "Core Domain Service",
        "responsibility": "Owns the order and shipment lifecycle. Publishes internal domain events (OrderPlaced, OrderConfirmed, etc.) to the internal event bus. Enforces all business invariants.",
        "boundaries": "Never communicates directly with any external system. Only speaks the internal ubiquitous language. All external interactions go through ACLs."
      },
      {
        "name": "Internal Event Bus (Kafka)",
        "responsibility": "Central nervous system. All domain events flow through topic 'logistics.domain.events' partitioned by orderId. Provides durable, ordered, replayable event log. Single source of truth for event history.",
        "boundaries": "Internal only. External systems never read from or write to internal topics directly."
      },
      {
        "name": "SAP ERP Adapter (System A ACL)",
        "responsibility": "Polls SFTP endpoint every 15 minutes. Parses XML order confirmations. Translates SAP order model into internal OrderConfirmed domain events. Handles XML schema versioning, validation, and error quarantine.",
        "boundaries": "Owns the SFTP connection, XML parsing, and SAP-specific data model. Exposes nothing SAP-specific beyond this boundary. Failed files go to a dead-letter directory for manual review."
      },
      {
        "name": "DHL Carrier Adapter (System B ACL)",
        "responsibility": "Outbound: translates ShipmentCreated events into DHL REST API calls to book shipments. Inbound: exposes a webhook endpoint that receives DHL status callbacks, translates them into internal DeliveryAttempted/DeliveryCompleted/DeliveryFailed events. Enforces 500ms webhook response SLA by immediately acknowledging and processing asynchronously.",
        "boundaries": "Owns DHL API client, webhook endpoint, DHL-specific data model, retry logic, and circuit breaker. DHL's model (tracking numbers, status codes) is never leaked into the core domain."
      },
      {
        "name": "Analytics Stream Adapter (System C ACL)",
        "responsibility": "Consumes all internal domain events from the event bus, transforms them into the analytics platform's schema, and produces them to an external-facing Kafka topic (or bridges to the analytics platform's Kafka cluster). Handles schema evolution for the analytics contract independently.",
        "boundaries": "Owns the mapping between internal event schema and analytics event schema. If the analytics platform changes its schema, only this adapter changes."
      },
      {
        "name": "Webhook Gateway",
        "responsibility": "Lightweight HTTP layer that receives DHL webhook callbacks. Performs signature verification, rate limiting, and request validation. Immediately returns 200 OK and enqueues the raw payload for async processing by the DHL Adapter.",
        "boundaries": "Stateless. No business logic. Sole purpose is to meet the 500ms SLA and protect the system from webhook floods."
      },
      {
        "name": "SFTP Poller",
        "responsibility": "Scheduled job that connects to SAP SFTP, lists new files, downloads them, and hands them to the SAP Adapter for parsing. Tracks processed files to avoid reprocessing (idempotency via filename/checksum registry).",
        "boundaries": "Owns SFTP connection lifecycle and file tracking. Separated from XML parsing to allow independent scaling and failure isolation."
      },
      {
        "name": "Dead Letter / Error Handling",
        "responsibility": "Captures failed integrations across all adapters: unparseable XML files, failed DHL API calls after retry exhaustion, analytics events that fail schema validation. Provides alerting and manual retry capabilities.",
        "boundaries": "Cross-cutting concern. Each adapter publishes to a shared dead-letter topic with adapter-specific metadata."
      }
    ],
    "interfaces": [
      {
        "from": "SFTP Poller",
        "to": "SAP ERP Adapter",
        "contract": "Raw XML byte stream + filename metadata. Poller hands off complete files; adapter owns parsing.",
        "coupling_type": "local async (internal queue or direct handoff within same deployment unit)"
      },
      {
        "from": "SAP ERP Adapter",
        "to": "Internal Event Bus",
        "contract": "Produces OrderConfirmed events to 'logistics.domain.events' topic. Event schema: {eventType, orderId, confirmedAt, lineItems[], sapReferenceId}",
        "coupling_type": "async (Kafka producer)"
      },
      {
        "from": "Core Domain Service",
        "to": "Internal Event Bus",
        "contract": "Produces all domain events (OrderPlaced, ShipmentCreated, etc.) with consistent envelope: {eventId, eventType, aggregateId, timestamp, version, payload}",
        "coupling_type": "async (Kafka producer, transactional outbox pattern)"
      },
      {
        "from": "Internal Event Bus",
        "to": "DHL Carrier Adapter",
        "contract": "Consumes ShipmentCreated events from 'logistics.domain.events'. Adapter filters by eventType.",
        "coupling_type": "async (Kafka consumer group 'dhl-adapter')"
      },
      {
        "from": "DHL Carrier Adapter",
        "to": "DHL REST API",
        "contract": "HTTPS POST to DHL shipment booking endpoint. JSON payload per DHL API spec. Circuit breaker with 3 failures / 30s window.",
        "coupling_type": "sync HTTP (outbound, with retry + circuit breaker)"
      },
      {
        "from": "DHL Webhooks",
        "to": "Webhook Gateway",
        "contract": "HTTPS POST from DHL with shipment status payload. Gateway returns 200 within 500ms unconditionally after basic validation.",
        "coupling_type": "sync HTTP (inbound, fire-and-forget acknowledgment)"
      },
      {
        "from": "Webhook Gateway",
        "to": "DHL Carrier Adapter",
        "contract": "Raw DHL webhook payload enqueued to 'dhl.inbound.raw' topic for async processing.",
        "coupling_type": "async (Kafka or internal queue)"
      },
      {
        "from": "DHL Carrier Adapter",
        "to": "Internal Event Bus",
        "contract": "Produces DeliveryAttempted, DeliveryCompleted, or DeliveryFailed events after translating DHL status codes.",
        "coupling_type": "async (Kafka producer)"
      },
      {
        "from": "Internal Event Bus",
        "to": "Analytics Stream Adapter",
        "contract": "Consumes ALL domain events from 'logistics.domain.events'. Consumer group 'analytics-adapter'.",
        "coupling_type": "async (Kafka consumer)"
      },
      {
        "from": "Analytics Stream Adapter",
        "to": "Analytics Platform Kafka",
        "contract": "Produces transformed events to external topic 'analytics.logistics.events' in analytics-specific Avro/JSON schema.",
        "coupling_type": "async (Kafka producer to external cluster, or MirrorMaker bridge)"
      }
    ],
    "data_flow": "1) Orders originate in the Core Domain (OrderPlaced) or arrive as confirmations from SAP via SFTP→Poller→SAP Adapter→OrderConfirmed event. 2) ShipmentCreated events trigger the DHL Adapter to book shipments via REST API. 3) DHL sends webhook callbacks to the Webhook Gateway, which acknowledges immediately and queues for the DHL Adapter to translate into delivery events. 4) ALL domain events (from Core, SAP Adapter, and DHL Adapter) flow through the Internal Event Bus. 5) The Analytics Adapter tails the entire event stream, transforms to the analytics schema, and forwards to the external analytics Kafka cluster. Dead letters capture failures at every integration point.",
    "patterns_used": [
      {
        "pattern": "Anti-Corruption Layer (ACL)",
        "rationale": "Each external system has its own data model, protocol, and failure modes. ACLs prevent SAP's XML model, DHL's REST model, and the analytics schema from polluting the core domain. When any external system changes its API, only its adapter changes."
      },
      {
        "pattern": "Event-Driven Architecture with Internal Event Bus",
        "rationale": "The six domain events are the natural integration points. An event bus decouples producers from consumers, enables replay for analytics catch-up, and allows adding new consumers (e.g., a future WMS integration) without modifying existing components."
      },
      {
        "pattern": "Transactional Outbox",
        "rationale": "The Core Domain Service writes domain events to an outbox table in the same transaction as state changes, then a relay publishes them to Kafka. This avoids dual-write problems where the database commits but Kafka publish fails (or vice versa)."
      },
      {
        "pattern": "Async Webhook Acknowledgment",
        "rationale": "DHL requires 500ms response time. By immediately returning 200 OK and queuing the payload for async processing, we guarantee the SLA regardless of processing time. This is the only correct approach for latency-constrained webhooks."
      },
      {
        "pattern": "Circuit Breaker (on DHL outbound calls)",
        "rationale": "DHL's REST API is an external dependency with unpredictable availability. A circuit breaker prevents cascading failures when DHL is down, allowing the system to queue shipment requests and retry when the circuit closes."
      },
      {
        "pattern": "Idempotent Consumer",
        "rationale": "Every adapter must handle duplicate events gracefully. SFTP files tracked by checksum, DHL webhooks deduplicated by trackingId+status, analytics events deduplicated by eventId. Kafka's at-least-once delivery makes this non-negotiable."
      },
      {
        "pattern": "Dead Letter Queue",
        "rationale": "Integration failures are inevitable. Poison messages (malformed XML, unrecognized DHL status codes, schema validation failures) must not block processing. Dead letter queues isolate failures and enable manual intervention."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management (Core Domain)",
        "classification": "core",
        "aggregates": ["Order (root: orderId, states: Placed→Confirmed→Shipped→Delivered/Failed)", "Shipment (root: shipmentId, linked to orderId, states: Created→InTransit→Delivered/Failed)"]
      },
      {
        "name": "ERP Integration (Supporting)",
        "classification": "supporting",
        "aggregates": ["SapOrderConfirmation (tracks processed SAP files and their mapping to internal orders)"]
      },
      {
        "name": "Carrier Integration (Supporting)",
        "classification": "supporting",
        "aggregates": ["CarrierShipment (tracks DHL booking state, tracking numbers, and webhook deduplication)"]
      },
      {
        "name": "Analytics Integration (Generic)",
        "classification": "generic",
        "aggregates": ["EventProjection (stateless transformer, no domain aggregates — pure stream processing)"]
      }
    ],
    "context_map": [
      {
        "upstream": "SAP ERP (external)",
        "downstream": "ERP Integration Context",
        "relationship": "Conformist — we conform to SAP's XML schema since we cannot influence it. The ACL translates SAP's model into our domain language at the boundary."
      },
      {
        "upstream": "ERP Integration Context",
        "downstream": "Order Management Context",
        "relationship": "Customer-Supplier — ERP Integration translates and publishes events that Order Management consumes. Order Management dictates what events it needs."
      },
      {
        "upstream": "Order Management Context",
        "downstream": "Carrier Integration Context",
        "relationship": "Customer-Supplier — Order Management publishes ShipmentCreated; Carrier Integration consumes and acts on it."
      },
      {
        "upstream": "DHL Carrier API (external)",
        "downstream": "Carrier Integration Context",
        "relationship": "Conformist with ACL — we conform to DHL's webhook payload format but translate immediately into our domain events."
      },
      {
        "upstream": "Order Management Context",
        "downstream": "Analytics Integration Context",
        "relationship": "Open Host Service / Published Language — Order Management publishes a well-defined event stream. Analytics consumes all events."
      },
      {
        "upstream": "Carrier Integration Context",
        "downstream": "Analytics Integration Context",
        "relationship": "Open Host Service — Carrier Integration publishes delivery events that Analytics also consumes."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Kafka as the internal event bus (not RabbitMQ, not direct HTTP)",
      "gains": "Durable replay for analytics catch-up, natural fit for System C's Kafka requirement, partitioned ordering by orderId, consumer group isolation so adapters scale independently",
      "sacrifices": "Operational complexity of running Kafka, higher latency than direct HTTP for simple cases (~5-50ms added), requires schema registry management",
      "alternatives_considered": ["RabbitMQ — simpler ops but no replay, poor fit for analytics Kafka requirement", "Direct HTTP between services — simpler but creates tight coupling and no event history", "AWS EventBridge — managed but vendor lock-in and less control over partitioning"]
    },
    {
      "decision": "Immediate webhook ACK with async processing (vs synchronous processing within 500ms)",
      "gains": "Guarantees 500ms SLA regardless of processing complexity, isolates DHL webhook reliability from internal system health",
      "sacrifices": "DHL won't know if processing actually succeeded (but webhooks are inherently unreliable anyway — DHL should retry on non-200), adds a queue between gateway and adapter",
      "alternatives_considered": ["Synchronous processing within 500ms — risky if processing involves DB writes or event publishing; one slow query and the SLA is blown"]
    },
    {
      "decision": "Transactional outbox pattern (vs dual-write to DB + Kafka)",
      "gains": "Exactly-once semantics between domain state and event publishing, no lost or phantom events",
      "sacrifices": "Added complexity of outbox table + relay process, slightly higher latency for event publication (relay polling interval)",
      "alternatives_considered": ["Dual write — simpler but fundamentally broken: DB can commit while Kafka fails, creating permanent inconsistency", "CDC (Debezium) — viable alternative but adds infrastructure dependency; outbox is simpler for this scale"]
    },
    {
      "decision": "Separate adapter per external system (vs unified integration service)",
      "gains": "Independent deployment, scaling, and failure isolation. SAP adapter's SFTP issues don't affect DHL webhook processing. Each adapter can use the optimal concurrency model for its protocol.",
      "sacrifices": "More deployment units to manage, potential duplication of some infrastructure code (Kafka producers, error handling)",
      "alternatives_considered": ["Single integration service — simpler deployment but creates a single point of failure and conflates unrelated concerns"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Adding new carrier integrations (FedEx, UPS)",
      "evolution_path": "Create a new Carrier Adapter that consumes ShipmentCreated events and produces the same delivery domain events. No changes to Core Domain or other adapters. The event bus makes this a pure addition."
    },
    {
      "area": "Replacing SAP with a different ERP",
      "evolution_path": "Replace the SAP Adapter with a new ERP adapter. As long as it produces OrderConfirmed events with the same schema, nothing downstream changes."
    },
    {
      "area": "Adding new event consumers (e.g., customer notifications, WMS)",
      "evolution_path": "New consumer group on the internal event bus. Zero changes to existing components. This is the primary advantage of the event-driven backbone."
    },
    {
      "area": "Changing analytics platform",
      "evolution_path": "Replace or modify the Analytics Stream Adapter. The internal event schema is stable; only the outbound transformation changes."
    }
  ],

  "rigidity_points": [
    {
      "area": "Internal domain event schema",
      "reason": "The event envelope (eventId, eventType, aggregateId, timestamp, version, payload) is the contract everything depends on. Changing it requires coordinated updates across all adapters. This rigidity is intentional — a stable internal contract is what enables flexibility at the edges."
    },
    {
      "area": "Kafka as infrastructure",
      "reason": "Choosing Kafka as the event bus is a deep commitment. Switching to a different messaging system later would require reworking every producer and consumer. This is acceptable because Kafka is the right tool here and the analytics platform already requires it."
    },
    {
      "area": "OrderId as the primary partition key",
      "reason": "All events for a given order land on the same Kafka partition, guaranteeing ordering. Changing the partitioning strategy later would require careful migration to avoid ordering violations."
    }
  ],

  "risks": [
    {
      "risk": "SAP SFTP polling gap: if a file is deposited and removed within the 15-minute window before the next poll, the order confirmation is lost",
      "severity": "high",
      "mitigation": "Negotiate with SAP team to keep files until explicitly acknowledged (move-after-read pattern). Poller moves processed files to an 'archive' directory rather than deleting. Add reconciliation job that compares SAP order IDs against internal confirmed orders daily."
    },
    {
      "risk": "DHL webhook delivery failure: DHL may not retry webhooks reliably, causing missed delivery status updates",
      "severity": "high",
      "mitigation": "Implement a polling fallback: a scheduled job queries DHL's tracking API for shipments that haven't received a status update within expected timeframes. Webhooks are the primary path; polling is the safety net."
    },
    {
      "risk": "Event ordering violations if multiple adapters produce events for the same orderId concurrently",
      "severity": "medium",
      "mitigation": "Kafka partitioning by orderId ensures ordering within a partition. Each adapter uses orderId as the message key. Consumers must handle eventual consistency — e.g., a DeliveryCompleted event may arrive before the consumer has seen ShipmentCreated if they're in different consumer groups. Use event versioning and sequence numbers."
    },
    {
      "risk": "Analytics adapter falls behind (consumer lag) during high-volume periods, causing stale analytics data",
      "severity": "medium",
      "mitigation": "Monitor consumer lag metrics. The analytics adapter is stateless and horizontally scalable — add partitions and consumer instances. Kafka's retention policy (7+ days) ensures no data loss during temporary lag."
    },
    {
      "risk": "Transactional outbox relay becomes a bottleneck under high throughput",
      "severity": "low",
      "mitigation": "Use CDC (Debezium) as a drop-in replacement for the polling relay if throughput exceeds polling capacity. The outbox table schema is compatible with both approaches."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in phases: Phase 1 — Core Domain Service with internal event bus and transactional outbox. Phase 2 — SAP Adapter (lowest risk, batch/polling). Phase 3 — DHL Adapter with webhook gateway (highest complexity). Phase 4 — Analytics adapter (pure consumer, lowest risk). Each phase is independently deployable and testable. Use contract tests at every ACL boundary to ensure adapters correctly translate external models.",
    "files_to_create_or_modify": [
      "src/core/domain/events/ — Domain event definitions (OrderPlaced, OrderConfirmed, ShipmentCreated, DeliveryAttempted, DeliveryCompleted, DeliveryFailed)",
      "src/core/domain/aggregates/ — Order and Shipment aggregate roots",
      "src/core/infrastructure/outbox/ — Transactional outbox table, relay process",
      "src/adapters/sap/ — SFTP poller, XML parser, SAP-to-domain event translator",
      "src/adapters/dhl/ — DHL REST client, webhook handler, DHL-to-domain event translator, circuit breaker config",
      "src/adapters/dhl/gateway/ — Webhook HTTP endpoint (lightweight, stateless)",
      "src/adapters/analytics/ — Event stream transformer, external Kafka producer",
      "src/shared/kafka/ — Kafka producer/consumer base classes, schema registry config",
      "src/shared/resilience/ — Circuit breaker, retry policies, dead letter publisher",
      "infrastructure/kafka/ — Topic definitions, partition configs, consumer group configs",
      "infrastructure/monitoring/ — Consumer lag alerts, dead letter queue alerts, SFTP polling health checks"
    ],
    "patterns_to_follow": "Hexagonal architecture (ports and adapters) for each bounded context. Each adapter implements an inbound or outbound port. Domain events use a versioned envelope schema with backward-compatible evolution (add fields, never remove). All external calls wrapped in circuit breakers. All consumers are idempotent. Use structured logging with correlationId (orderId) across all components for distributed tracing.",
    "pitfalls_to_avoid": [
      "DO NOT let SAP's XML schema leak into domain events — translate at the boundary, even if it means duplicating some field names",
      "DO NOT process DHL webhooks synchronously — the 500ms SLA will be violated under load or when downstream services are slow",
      "DO NOT use Kafka transactions across multiple topics — use the outbox pattern instead for cross-concern atomicity",
      "DO NOT share Kafka consumer groups between adapters — each adapter needs independent consumption progress",
      "DO NOT skip idempotency handling because 'it probably won't happen' — duplicate messages are guaranteed in any at-least-once system",
      "DO NOT put business logic in adapters — adapters translate and forward, the Core Domain Service owns all invariants"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "Event-driven backbone with Kafka is the correct architectural choice given the three integration patterns and the analytics Kafka requirement",
      "ACL per external system is non-negotiable — the three systems have fundamentally different protocols, data models, and reliability characteristics",
      "Async webhook acknowledgment is the only correct approach for the 500ms DHL SLA",
      "Transactional outbox prevents the dual-write consistency problem"
    ],
    "low_confidence_areas": [
      "Exact SFTP polling strategy depends on SAP's file retention policy, which is an external constraint not specified",
      "Whether the analytics platform requires its own Kafka cluster or can share topics on the internal cluster — affects the Analytics Adapter's complexity",
      "Volume and throughput requirements are unspecified — the architecture handles moderate scale; extreme scale (millions of events/sec) would require different partitioning and potentially CQRS"
    ],
    "assumptions": [
      "Order volumes are moderate (thousands to tens of thousands per day, not millions)",
      "SAP SFTP is a standard SFTP server with predictable file naming conventions",
      "DHL's webhook format is stable and well-documented",
      "The analytics platform can consume from a Kafka topic (either shared cluster or via MirrorMaker/bridge)",
      "The team has Kafka operational expertise or is willing to use a managed Kafka service"
    ]
  }
}

